import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate, Link } from "react-router-dom";

function ViewProduct()
{
    const navigate = useNavigate();// Use useNavigate for redirection
    const [loading, setLoading] = useState(true);
    const [products, setProducts] = useState([]);
    const [category, setCategory] = useState([]);

    const productCount = products.length;

    useEffect(() =>
    {
        let isMounted = true;


        const product_slug = props.match.params.slug;
        axios.get(`/api/fetchProducts/${product_slug}`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setProducts(res.data.products_data.products);
                    setCategory(res.data.products_data.category);
                    setLoading(false);
                }
                else if (res.data.status === 400)
                {
                    Swal.fire("Warning", res.data.message, "");
                }
                else if (res.data.status === 404)
                {
                    // Use navigate for redirection
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [props.match.params.slug, navigate]);




    // Render the products page
    if (loading)
    {
        return <h4>Loading Products...</h4>;
    }
    else
    {
        var showProductList = "";
        if (productCount)
        {
            showProductList = products.map((item, idx) =>
            {
                return (
                    <div className="col-md-3" key={idx}>
                        <div className="card">
                            <Link to={`/collections/${item.category.slug}/${item.slug}`}>
                                <img src={`http://localhost:8000/${item.image}`} className="w-100" alt={item.name} />
                            </Link>
                            <div className="card-body">
                                <Link to={`/collections/${item.category.slug}/${item.slug}`}>
                                    <h5>{item.name}</h5>
                                </Link>
                            </div>
                        </div>
                    </div>
                )
            });
        }
        else
        {
            showProductList =
                <div className="col-md-12 text-center">
                    <h4>No Products Available for {category.name}</h4>
                </div>
        }
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Collections / {category.name}</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">
                        {showProductList}
                    </div>
                </div>
            </div>
        </div>
    );
};
export default ViewProduct;
